const d = $json || {};
const h = d.headers || {};
const b = (d.body && typeof d.body === 'object') ? d.body : {};
const q = d.query || {};
// ManyChat delivers text/name via HTTP headers (latin1), so UTF-8 chars
// (smart quotes, emoji, accents) arrive double-encoded. Recover the original.
function fixEnc(s){ if(!s) return s; try { const r = Buffer.from(s,'latin1').toString('utf8'); return r.includes('\uFFFD') ? s : r; } catch(e){ return s; } }
const msg = fixEnc((h.last_text_input || b.last_text_input || b.message || b.text || b.last_input_text || b.last_input || b.user_message || b.msg || q.last_text_input || q.message || q.text || '').toString()).replace(/^\s*\.+\s*/, '').trim();
// platform display name: ManyChat sends it as tiktok_display / system_firstname.
// ignore unresolved ManyChat placeholders like {{last_name}}.
function cleanName(s){ s=(s==null?'':String(s)).trim(); if(!s || /^\{\{.*\}\}$/.test(s)) return ''; return s; }
const display = fixEnc(cleanName(h.tiktok_display) || cleanName(h.system_firstname) || cleanName(h.tiktok_displayname) || cleanName(b.display_name) || cleanName(b.first_name) || cleanName(q.display) || cleanName(q.displayname) || 'him');
const username = (h.tiktok_username || b.username || q.username || display || 'unknown').toString().toLowerCase();
const subscriber_id = (h.subscriber_id || b.subscriber_id || b.user_id || q.subscriber_id || q.user_id || '').toString().trim();
const interaction = (h.tiktok_lastinteraction || b.tiktok_lastinteraction || q.tiktok_lastinteraction || '').toString().trim();
