const STALL_RE = /can'?t\s+(sign|log)\s*in|not\s+working|won'?t\s+(work|let|load)|having\s+trouble|help\s+me|been\s+busy|second\s+chance|sweet\s*talk|talk\s+dirty|tease\s+me|show\s+me|photo|prove|before\s+i\s+(send|add|sign|pay|join)/i;
const nonsense = /do you wanna crack|i'?ll eyp|wanna crack/i.test(L1);
const hostile = (cls.intent === 'insult') || /kill yourself|\bcunt\b|pathetic|report you|\bscam\b|wanker|piece of shit/i.test(L1);

let score = Math.round(num(prev.troll_score, 0) * decay);
let stall = num(prev.stall_hits, 0);

if (botTest && turns > num(cfg.bot_test_after_turn, D.bot_test_after_turn)) score += W.bot_test_repeat;
if (laugh) score += W.mockery;
if (performFirst) score += W.perform_first;
if (money && funnelled) score += W.empty_money;
if (proof) score += W.proof_demand;
if (nonsense) score += W.nonsense;
if (cls.zero_intent === true) score += W.zero_intent;
if (funnelled && STALL_RE.test(last)) { stall += 1; score += W.stall_hit; }

// cool-downs: genuine signals pull the score back down
if (/\b(i'?m|im|my)\s+(from|name|job|work|dog|cat|mom|dad|sister|brother|birthday|feel|felt|had a|really|actually)\b/i.test(L1) && !laugh && !botTest) score -= CD.personal_disclosure;
if (cls.intent === 'vulnerable') score -= CD.vulnerable;
if (stage === 'converted') score -= CD.concrete_step;

if (hostile) score = Math.max(score, W.hostility_floor);
score = Math.max(0, Math.min(100, score));

let mode = score >= B.ghost ? 'ghost' : score >= B.minimal ? 'minimal' : score >= B.cool ? 'cool' : 'engage';
if (stall >= L.ghost_at) mode = 'ghost';
else if (stall >= L.minimal_at && mode === 'engage') mode = 'minimal';
else if (stall >= L.callout_at && mode === 'engage') mode = 'cool';
const would_be = mode;

// disabled or shadow mode: compute + persist, but never change behaviour
if (!enabled || shadow) mode = 'engage';
// at minimal, sometimes just skip the reply entirely
if (mode === 'minimal' && Math.random() > num(cfg.minimal_reply_chance, D.minimal_reply_chance)) mode = 'ghost';

// no-response penalty: send nothing this turn
if (mode === 'ghost') { return []; }

const directiveByMode = {
  cool: 'he is likely wasting your time. be cooler and shorter, give him less. do NOT offer telegram again, do NOT perform on demand, do NOT help him with any app or signup. one dry statement.' + (stall >= L.callout_at ? ' call it out once, lightly: he keeps saying that and never does it.' : ''),
  minimal: 'he is a confirmed time waster. one short flat unbothered line. no telegram, no performing, no help, no question.',
  engage: cls.directive || 'stay cool and playful, be the prize, keep it short.'
};
let extra = 0;
if (would_be === 'minimal') extra = DP.minimal_base_sec + stall * DP.minimal_per_stall_sec;
else if (would_be === 'cool') extra = DP.cool_sec;
if (shadow || !enabled) extra = 0;

return [{ json: Object.assign({}, $json, { gate: {
  mode: mode, would_be_mode: would_be, troll_score: score, stall_hits: stall,
  no_funnel: (mode !== 'engage'), directive: directiveByMode[mode],
  extra_delay_sec: extra, shadow: shadow, enabled: enabled
}})}];

// hold gate: honour a dashboard-set send_after ("+15m" button). waits the
// remainder (once) before the reply proceeds. capped at 6h for safety.
var a = $('DB: get fan').first().json;
var row = Array.isArray(a) ? (a[0]||{}) : (a||{});
var sec = 0;
if (row && row.send_after) {
  var t = new Date(row.send_after).getTime();
  if (!isNaN(t)) { sec = Math.round((t - Date.now())/1000); }
  if (sec < 0) sec = 0;
  if (sec > 21600) sec = 21600;
}
return [{ json: { hold_sec: sec } }];
